import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Установка Java на Linux","description":"Пошаговая инструкция по установке Java на Linux.","frontmatter":{"title":"Установка Java на Linux","description":"Пошаговая инструкция по установке Java на Linux.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ru_ru/1.20.4/players/installing-java/linux.md","filePath":"versions/1.20.4/translated/ru_ru/players/installing-java/linux.md","lastUpdated":1739538073000}`);var o={name:`ru_ru/1.20.4/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Java на Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Java на Linux”">​</a></h1><p>Этот гайд расскажет, как установить Java 17 на Linux.</p><h2 id="_1-проверьте-не-установлена-ли-java" tabindex="-1">1. Проверьте, не установлена ли Java <a class="header-anchor" href="#_1-проверьте-не-установлена-ли-java" aria-label="Permalink to “1. Проверьте, не установлена ли Java”">​</a></h2><p>Откройте терминал, впишите <code>java -version</code> и нажмите <kbd>Enter</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Терминал с введённой командой &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Чтобы использовать большинство современных версий Minecraft, вам потребуется установить как минимум Java 17. Если эта команда отображает любую версию ниже 17, вам придётся обновить Java.</p></div><h2 id="_2-загрузка-и-установка-java-17" tabindex="-1">2. Загрузка и установка Java 17 <a class="header-anchor" href="#_2-загрузка-и-установка-java-17" aria-label="Permalink to “2. Загрузка и установка Java 17”">​</a></h2><p>Мы рекомендуем использовать OpenJDK 17, который доступен для большинства дистрибутивов Linux.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Для дополнительной информации об установке Java в Arch Linux смотрите <a href="https://wiki.archlinux.org/title/Java_(%D0%A0%D1%83%D1%81%D1%81%D0%BA%D0%B8%D0%B9)" target="_blank" rel="noreferrer">википедию Arch Linux</a>.</p></div><p>Вы можете установить последнюю версию JRE из официальных репозиториев:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Если вы используете сервер без необходимости в графическом интерфейсе, вы можете вместо этого установить <code>headless</code> версию:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Если вы планируете разрабатывать моды, вместо этого вам понадобится JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>Вы можете установить Java 17, используя <code>apt</code>, с помощью следующих команд:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-17-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>Вы можете установить Java 17, используя <code>dnf</code>, с помощью следующих команд:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Если вам не нужен графический интерфейс, вы можете вместо этого установить <code>headless</code> версию:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Если вы планируете разрабатывать моды, вместо этого вам понадобится JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="другие-дистрибутивы-linux" tabindex="-1">Другие дистрибутивы Linux <a class="header-anchor" href="#другие-дистрибутивы-linux" aria-label="Permalink to “Другие дистрибутивы Linux”">​</a></h3><p>Если вашего дистрибутива нет в списке выше, вы можете загрузить последнюю версию JRE с <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a></p><p>Вам следует обратиться к альтернативному гайду для вашего дистрибутива, если вы планируете разрабатывать моды.</p><h2 id="_3-убедитесь-что-java-17-установлена" tabindex="-1">3. Убедитесь, что Java 17 установлена <a class="header-anchor" href="#_3-убедитесь-что-java-17-установлена" aria-label="Permalink to “3. Убедитесь, что Java 17 установлена”">​</a></h2><p>После того как установка закончится, вы можете проверить, что Java 17 установлена, открыв терминал и вписав <code>java -version</code>.</p><p>Если команда будет выполнена успешно, вы увидите что-то вроде показанного ранее, где отображается версия Java:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Терминал с введённой командой &quot;java -version&quot;" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};